/* ai essentials :: content/quiz2.js  (Domain 2 question bank - Prompt Engineering) */
window.AIESS = window.AIESS || {}; AIESS.questions = AIESS.questions || [];
AIESS.questions.push(
/* ===================== Objective 2.1 - The GOAL building block ===================== */
{ id:"D2-001", domain:2, obj:"2.1", diff:"easy", q:"Which building block of a prompt states the specific outcome you want the AI to produce?", options:["Goal","Persona","Context","Constraint"], answer:0, explain:"<strong>Goal</strong> is the building block that states the desired outcome or deliverable, telling the AI exactly what you want it to produce.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Persona</b>: persona sets the role the AI should adopt, not the outcome you want.</span><span class='qd'><b>Context</b>: context supplies background and situation, but it does not name the deliverable itself.</span><span class='qd'><b>Constraint</b>: a constraint limits how the output is produced, such as length or tone, rather than defining the goal.</span>" },
{ id:"D2-002", domain:2, obj:"2.1", diff:"easy", q:"A user types &quot;Help me with my email.&quot; Why is this a weak GOAL?", options:["It names the wrong persona","It does not say what outcome is actually wanted","It gives too many constraints","It attaches an unnecessary file"], answer:1, explain:"<strong>It does not say what outcome is actually wanted</strong> because &quot;help me with my email&quot; never states whether to write, shorten, proofread, or reply, leaving the AI to guess.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It names the wrong persona</b>: the prompt names no persona at all, so a wrong one is not the issue.</span><span class='qd'><b>It gives too many constraints</b>: the prompt provides no constraints, which is part of why it is weak, not the reverse.</span><span class='qd'><b>It attaches an unnecessary file</b>: no file is attached, so that is not the flaw.</span>" },
{ id:"D2-003", domain:2, obj:"2.1", diff:"easy", q:"Which prompt states the clearest GOAL?", options:["&quot;Something about our new product.&quot;","&quot;You are a marketer.&quot;","&quot;Write a 100-word product announcement for our new water bottle.&quot;","&quot;Our company sells water bottles.&quot;"], answer:2, explain:"<strong>&quot;Write a 100-word product announcement for our new water bottle.&quot;</strong> names a concrete deliverable — a product announcement of a set length about a specific item — which is a clear goal.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;Something about our new product.&quot;</b>: this is vague and never says what to create.</span><span class='qd'><b>&quot;You are a marketer.&quot;</b>: this sets a persona but states no outcome to produce.</span><span class='qd'><b>&quot;Our company sells water bottles.&quot;</b>: this is background context, not a request for any deliverable.</span>" },
{ id:"D2-004", domain:2, obj:"2.1", diff:"easy", q:"In prompt engineering, the GOAL is best described as:", options:["The tone the AI should use","A file you attach for reference","The AI's assumed job title","The desired result you want from the AI"], answer:3, explain:"<strong>The desired result you want from the AI</strong> is exactly what the goal expresses — the end product or answer you are asking for.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The tone the AI should use</b>: tone is a constraint on style, not the goal itself.</span><span class='qd'><b>A file you attach for reference</b>: an attached file is contextual material, not the goal.</span><span class='qd'><b>The AI's assumed job title</b>: the assumed role is the persona, not the goal.</span>" },
{ id:"D2-005", domain:2, obj:"2.1", diff:"medium", q:"A manager writes: &quot;Make this better.&quot; What single change would most improve the GOAL?", options:["State what &quot;better&quot; means, such as &quot;make it more concise and professional&quot;","Add an emoji to sound friendlier","Tell the AI to respond quickly","Ask the AI to guess the intent"], answer:0, explain:"<strong>State what &quot;better&quot; means, such as &quot;make it more concise and professional&quot;</strong> turns a vague wish into a measurable outcome the AI can actually act on.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Add an emoji to sound friendlier</b>: an emoji does nothing to clarify what improvement is wanted.</span><span class='qd'><b>Tell the AI to respond quickly</b>: response speed is irrelevant to defining the goal.</span><span class='qd'><b>Ask the AI to guess the intent</b>: making the AI guess is the exact problem a clear goal solves.</span>" },
{ id:"D2-006", domain:2, obj:"2.1", diff:"medium", q:"You want the AI to create a comparison of two software tools. Which phrasing sets the strongest GOAL?", options:["&quot;Tell me about software.&quot;","&quot;Compare Tool A and Tool B and recommend which suits a small team.&quot;","&quot;Software tools are important.&quot;","&quot;You are a software expert.&quot;"], answer:1, explain:"<strong>&quot;Compare Tool A and Tool B and recommend which suits a small team.&quot;</strong> names a precise deliverable — a comparison plus a recommendation for a defined audience.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;Tell me about software.&quot;</b>: this is far too broad and produces no useful comparison.</span><span class='qd'><b>&quot;Software tools are important.&quot;</b>: this is a statement, not a request for output.</span><span class='qd'><b>&quot;You are a software expert.&quot;</b>: this assigns a persona but never states what to compare or produce.</span>" },
{ id:"D2-007", domain:2, obj:"2.1", diff:"medium", q:"Why does a clearly stated GOAL usually produce a more useful AI response?", options:["It forces the AI to write longer answers","It removes the need for any context","It gives the AI a specific target to aim its output at","It hides the AI's reasoning"], answer:2, explain:"<strong>It gives the AI a specific target to aim its output at</strong>, so the model can focus on producing the exact deliverable rather than guessing among possibilities.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It forces the AI to write longer answers</b>: a clear goal often shortens output when brevity is requested; length is not the point.</span><span class='qd'><b>It removes the need for any context</b>: goal and context are complementary; a goal does not eliminate context.</span><span class='qd'><b>It hides the AI's reasoning</b>: a goal has nothing to do with concealing reasoning.</span>" },
{ id:"D2-008", domain:2, obj:"2.1", diff:"medium", q:"A student prompts: &quot;Explain photosynthesis.&quot; Which added detail most sharpens the GOAL for their needs?", options:["&quot;...you are a scientist.&quot;","&quot;...here is my biology textbook.&quot;","&quot;...respond in a serious tone.&quot;","&quot;...in a way a fifth-grader can understand, in about five sentences.&quot;"], answer:3, explain:"<strong>&quot;...in a way a fifth-grader can understand, in about five sentences.&quot;</strong> refines the goal by defining the target reading level and scope, making the requested outcome specific.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;...you are a scientist.&quot;</b>: this adds a persona, not a sharper goal.</span><span class='qd'><b>&quot;...here is my biology textbook.&quot;</b>: this adds context/source material, not the goal definition.</span><span class='qd'><b>&quot;...respond in a serious tone.&quot;</b>: this is a tone constraint, not a clarification of what to produce.</span>" },
{ id:"D2-009", domain:2, obj:"2.1", diff:"medium", q:"Which of the following is a GOAL rather than a constraint or persona?", options:["&quot;Draft a three-day itinerary for a trip to Rome.&quot;","&quot;Keep it under 200 words.&quot;","&quot;Act as a travel agent.&quot;","&quot;Use a friendly, casual tone.&quot;"], answer:0, explain:"<strong>&quot;Draft a three-day itinerary for a trip to Rome.&quot;</strong> names the deliverable to create, which is the goal.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;Keep it under 200 words.&quot;</b>: this is a length constraint, not the outcome itself.</span><span class='qd'><b>&quot;Act as a travel agent.&quot;</b>: this sets a persona, not the goal.</span><span class='qd'><b>&quot;Use a friendly, casual tone.&quot;</b>: this is a tone constraint.</span>" },
{ id:"D2-010", domain:2, obj:"2.1", diff:"hard", q:"An analyst writes: &quot;Give me insights on the sales data&quot; but attaches nothing and never says what decision the insights support. Which revision most improves the GOAL specifically?", options:["&quot;Give me lots of insights on the sales data.&quot;","&quot;Identify the three biggest month-over-month sales changes and what likely drove each.&quot;","&quot;You are a data analyst reviewing sales data.&quot;","&quot;Please respond in a professional tone.&quot;"], answer:1, explain:"<strong>&quot;Identify the three biggest month-over-month sales changes and what likely drove each.&quot;</strong> converts a vague ask into a precise, countable deliverable, which is what strengthening a goal means.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;Give me lots of insights on the sales data.&quot;</b>: &quot;lots of&quot; is still vague and defines no specific outcome.</span><span class='qd'><b>&quot;You are a data analyst reviewing sales data.&quot;</b>: this improves the persona, not the goal.</span><span class='qd'><b>&quot;Please respond in a professional tone.&quot;</b>: this adds a tone constraint, not a clearer goal.</span>" },
{ id:"D2-011", domain:2, obj:"2.1", diff:"hard", q:"Two prompts differ only in their goal statement. Prompt X: &quot;Summarize this report.&quot; Prompt Y: &quot;Summarize this report into five bullet points a busy executive can read in 30 seconds.&quot; Why is Y's GOAL stronger?", options:["It specifies who the persona is","It attaches a contextual file","It defines the output format and audience so the result is measurable","It uses a more formal tone"], answer:2, explain:"<strong>It defines the output format and audience so the result is measurable</strong> — five bullet points for a busy executive tells the AI precisely what a successful summary looks like.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It specifies who the persona is</b>: Y describes the reader, not a role the AI should take on.</span><span class='qd'><b>It attaches a contextual file</b>: neither prompt attaches a file; the difference is the goal wording.</span><span class='qd'><b>It uses a more formal tone</b>: tone is not what distinguishes the two goals.</span>" },
{ id:"D2-012", domain:2, obj:"2.1", diff:"hard", q:"A marketer needs the AI to produce three subject-line options for one campaign email. Which prompt communicates that GOAL most precisely?", options:["&quot;Write email subject lines.&quot;","&quot;You are an email marketing pro.&quot;","&quot;Make the subject line catchy.&quot;","&quot;Give me three distinct subject-line options for a spring-sale email, each under 50 characters.&quot;"], answer:3, explain:"<strong>&quot;Give me three distinct subject-line options for a spring-sale email, each under 50 characters.&quot;</strong> states the count, the purpose, and a measurable limit, defining the goal precisely.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;Write email subject lines.&quot;</b>: this gives no count, topic, or limit.</span><span class='qd'><b>&quot;You are an email marketing pro.&quot;</b>: this is a persona, not the goal.</span><span class='qd'><b>&quot;Make the subject line catchy.&quot;</b>: &quot;catchy&quot; is subjective and specifies no measurable outcome.</span>" },
{ id:"D2-013", domain:2, obj:"2.1", diff:"easy", q:"Which question should you ask yourself to define a strong GOAL before prompting?", options:["&quot;What exactly do I want the AI to produce?&quot;","&quot;What tone should the AI take?&quot;","&quot;Which file should I attach?&quot;","&quot;What role should the AI play?&quot;"], answer:0, explain:"<strong>&quot;What exactly do I want the AI to produce?&quot;</strong> is the core question behind the goal building block, because it forces you to name the deliverable.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;What tone should the AI take?&quot;</b>: tone is a constraint question, not the goal.</span><span class='qd'><b>&quot;Which file should I attach?&quot;</b>: attachments relate to context, not the goal.</span><span class='qd'><b>&quot;What role should the AI play?&quot;</b>: role selection defines the persona, not the goal.</span>" },
{ id:"D2-014", domain:2, obj:"2.1", diff:"medium", q:"A user asks the AI to &quot;brainstorm.&quot; Which addition turns this into a usable GOAL?", options:["&quot;...you are creative.&quot;","&quot;...brainstorm ten low-cost marketing ideas for a new coffee shop.&quot;","&quot;...be quick about it.&quot;","&quot;...here is a coffee menu.&quot;"], answer:1, explain:"<strong>&quot;...brainstorm ten low-cost marketing ideas for a new coffee shop.&quot;</strong> gives the AI a count, a constraint theme, and a subject, making the goal actionable.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;...you are creative.&quot;</b>: this is a persona hint, not a defined goal.</span><span class='qd'><b>&quot;...be quick about it.&quot;</b>: this addresses speed, not the deliverable.</span><span class='qd'><b>&quot;...here is a coffee menu.&quot;</b>: this is context, and alone it still does not say what to brainstorm.</span>" },
{ id:"D2-015", domain:2, obj:"2.1", diff:"medium", q:"Which pair shows a WEAK goal on the left and a STRONG goal on the right?", options:["&quot;Draft a resignation letter&quot; / &quot;Write something&quot;","&quot;List five ideas&quot; / &quot;Do the thing&quot;","&quot;Write something&quot; / &quot;Draft a two-paragraph resignation letter giving two weeks' notice&quot;","&quot;Summarize in three bullets&quot; / &quot;Help me out&quot;"], answer:2, explain:"<strong>&quot;Write something&quot; / &quot;Draft a two-paragraph resignation letter giving two weeks' notice&quot;</strong> correctly pairs a vague ask with a specific, well-scoped deliverable.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;Draft a resignation letter&quot; / &quot;Write something&quot;</b>: this reverses them, putting the strong goal first and the weak one second.</span><span class='qd'><b>&quot;List five ideas&quot; / &quot;Do the thing&quot;</b>: this reverses them as well, ending on the vague ask.</span><span class='qd'><b>&quot;Summarize in three bullets&quot; / &quot;Help me out&quot;</b>: this also reverses the order, placing the weak goal on the right.</span>" },
{ id:"D2-016", domain:2, obj:"2.1", diff:"medium", q:"An employee wants the AI to turn meeting notes into action items. Which sentence expresses that GOAL?", options:["&quot;You are a project manager.&quot;","&quot;Meetings can be long.&quot;","&quot;Keep it under 300 words.&quot;","&quot;Extract a list of action items, each with an owner, from these meeting notes.&quot;"], answer:3, explain:"<strong>&quot;Extract a list of action items, each with an owner, from these meeting notes.&quot;</strong> names the exact output — an owner-tagged action list — which is the goal.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;You are a project manager.&quot;</b>: this is a persona statement.</span><span class='qd'><b>&quot;Meetings can be long.&quot;</b>: this is filler context with no requested output.</span><span class='qd'><b>&quot;Keep it under 300 words.&quot;</b>: this is a length constraint, not the goal.</span>" },
{ id:"D2-017", domain:2, obj:"2.1", diff:"hard", q:"A prompt says: &quot;Write a blog post, an email, and a tweet about our launch.&quot; A colleague argues the GOAL is unfocused. What is the strongest reason?", options:["It bundles three different deliverables, so no single outcome is clearly scoped","It names too specific an audience","It adds an unnecessary persona","It uses too formal a tone"], answer:0, explain:"<strong>It bundles three different deliverables, so no single outcome is clearly scoped</strong> — asking for a blog post, email, and tweet at once dilutes focus and often yields shallow results for each.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It names too specific an audience</b>: the prompt actually names no audience, so specificity is not the problem.</span><span class='qd'><b>It adds an unnecessary persona</b>: no persona is present in the prompt.</span><span class='qd'><b>It uses too formal a tone</b>: the prompt sets no tone at all.</span>" },
{ id:"D2-018", domain:2, obj:"2.1", diff:"easy", q:"Which word or phrase in a prompt most directly signals the GOAL?", options:["&quot;Act as...&quot;","&quot;Write a...&quot;","&quot;Given that...&quot;","&quot;Limit it to...&quot;"], answer:1, explain:"<strong>&quot;Write a...&quot;</strong> is an action verb that names what to produce, directly signaling the goal.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;Act as...&quot;</b>: this introduces a persona.</span><span class='qd'><b>&quot;Given that...&quot;</b>: this introduces context or background.</span><span class='qd'><b>&quot;Limit it to...&quot;</b>: this introduces a constraint.</span>" },
{ id:"D2-019", domain:2, obj:"2.1", diff:"medium", q:"You need the AI to convert a paragraph into a table. Which prompt states the GOAL best?", options:["&quot;Tables are useful.&quot;","&quot;You are good with data.&quot;","&quot;Turn this paragraph into a two-column table of features and benefits.&quot;","&quot;Please be thorough.&quot;"], answer:2, explain:"<strong>&quot;Turn this paragraph into a two-column table of features and benefits.&quot;</strong> defines the transformation and the exact structure wanted, which is the goal.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;Tables are useful.&quot;</b>: this is an observation, not a request.</span><span class='qd'><b>&quot;You are good with data.&quot;</b>: this is a persona compliment, not a goal.</span><span class='qd'><b>&quot;Please be thorough.&quot;</b>: this is a vague quality constraint, not a defined outcome.</span>" },
{ id:"D2-020", domain:2, obj:"2.1", diff:"hard", q:"Which revision transforms the vague goal &quot;fix my writing&quot; into a precise, outcome-focused GOAL?", options:["&quot;Fix my writing and make it good.&quot;","&quot;You are an editor who fixes writing.&quot;","&quot;My writing has some problems.&quot;","&quot;Proofread this paragraph for grammar and spelling, and return the corrected version only.&quot;"], answer:3, explain:"<strong>&quot;Proofread this paragraph for grammar and spelling, and return the corrected version only.&quot;</strong> specifies the exact task and the desired form of the output, making the goal precise.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;Fix my writing and make it good.&quot;</b>: &quot;good&quot; is subjective and defines no measurable outcome.</span><span class='qd'><b>&quot;You are an editor who fixes writing.&quot;</b>: this sets a persona rather than the goal.</span><span class='qd'><b>&quot;My writing has some problems.&quot;</b>: this is background context with no requested deliverable.</span>" },

/* ===================== Objective 2.2 - The PERSONA building block ===================== */
{ id:"D2-021", domain:2, obj:"2.2", diff:"easy", q:"Which building block tells the AI what role or expertise to adopt when responding?", options:["Persona","Goal","Constraint","Contextual file"], answer:0, explain:"<strong>Persona</strong> is the building block that assigns the AI a role or expertise, such as &quot;act as a career coach,&quot; shaping how it responds.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Goal</b>: the goal names the outcome, not the role the AI takes.</span><span class='qd'><b>Constraint</b>: a constraint limits format or length, not the AI's role.</span><span class='qd'><b>Contextual file</b>: an attached file supplies source material, not a role.</span>" },
{ id:"D2-022", domain:2, obj:"2.2", diff:"easy", q:"Which phrase assigns a PERSONA to the AI?", options:["&quot;In 100 words or fewer...&quot;","&quot;Act as an experienced nutritionist...&quot;","&quot;Here is my grocery list...&quot;","&quot;Recommend three meals...&quot;"], answer:1, explain:"<strong>&quot;Act as an experienced nutritionist...&quot;</strong> tells the AI which expert role to take on, which is the persona.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;In 100 words or fewer...&quot;</b>: this is a length constraint.</span><span class='qd'><b>&quot;Here is my grocery list...&quot;</b>: this supplies context.</span><span class='qd'><b>&quot;Recommend three meals...&quot;</b>: this states the goal.</span>" },
{ id:"D2-023", domain:2, obj:"2.2", diff:"easy", q:"A PERSONA in a prompt can describe:", options:["Only the AI's role","Only the file format","Both the AI's role and your own role","Only the word count"], answer:2, explain:"<strong>Both the AI's role and your own role</strong> can be set in the persona — telling the AI who it is and who you are helps it tailor the response appropriately.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Only the AI's role</b>: stating your own role (for example, &quot;I am a beginner&quot;) is also part of persona.</span><span class='qd'><b>Only the file format</b>: file format is a constraint, not persona.</span><span class='qd'><b>Only the word count</b>: word count is a constraint, not persona.</span>" },
{ id:"D2-024", domain:2, obj:"2.2", diff:"medium", q:"You are a complete beginner asking the AI about investing. Which persona detail about YOURSELF most improves the answer?", options:["&quot;I already have an MBA in finance.&quot;","&quot;Respond in exactly 500 words.&quot;","&quot;Here is a stock chart.&quot;","&quot;I am new to investing and unfamiliar with financial jargon.&quot;"], answer:3, explain:"<strong>&quot;I am new to investing and unfamiliar with financial jargon.&quot;</strong> tells the AI your level so it can explain in plain language, which is your side of the persona.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;I already have an MBA in finance.&quot;</b>: this is false for a beginner and would make the answer too advanced.</span><span class='qd'><b>&quot;Respond in exactly 500 words.&quot;</b>: this is a length constraint, not a persona detail.</span><span class='qd'><b>&quot;Here is a stock chart.&quot;</b>: this is context, not a statement of your role.</span>" },
{ id:"D2-025", domain:2, obj:"2.2", diff:"easy", q:"Which prompt uses a PERSONA to get more expert-sounding output?", options:["&quot;As a senior IT consultant, explain cloud computing to a small-business owner.&quot;","&quot;Explain cloud computing.&quot;","&quot;Cloud computing is popular.&quot;","&quot;Keep the explanation short.&quot;"], answer:0, explain:"<strong>&quot;As a senior IT consultant, explain cloud computing to a small-business owner.&quot;</strong> assigns an expert role and an audience, so the AI frames its answer from that expertise.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;Explain cloud computing.&quot;</b>: this states a goal but adopts no role.</span><span class='qd'><b>&quot;Cloud computing is popular.&quot;</b>: this is a background statement.</span><span class='qd'><b>&quot;Keep the explanation short.&quot;</b>: this is a constraint.</span>" },
{ id:"D2-026", domain:2, obj:"2.2", diff:"medium", q:"Why can adding a well-chosen PERSONA improve an AI response?", options:["It guarantees the answer is factually perfect","It steers the AI's vocabulary, depth, and perspective toward the assigned role","It shortens every response automatically","It replaces the need for a goal"], answer:1, explain:"<strong>It steers the AI's vocabulary, depth, and perspective toward the assigned role</strong>, so a &quot;lawyer&quot; persona sounds different from a &quot;kindergarten teacher&quot; persona for the same question.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It guarantees the answer is factually perfect</b>: a persona shapes style, not factual accuracy, and never guarantees correctness.</span><span class='qd'><b>It shortens every response automatically</b>: length is governed by constraints, not persona.</span><span class='qd'><b>It replaces the need for a goal</b>: you still need a goal even with a persona set.</span>" },
{ id:"D2-027", domain:2, obj:"2.2", diff:"medium", q:"A teacher wants feedback written the way a supportive mentor would give it. Which persona instruction fits?", options:["&quot;Respond as a strict examiner who only lists errors.&quot;","&quot;Limit the feedback to 20 words.&quot;","&quot;Act as an encouraging writing mentor who gives balanced, constructive feedback.&quot;","&quot;Here is the essay rubric.&quot;"], answer:2, explain:"<strong>&quot;Act as an encouraging writing mentor who gives balanced, constructive feedback.&quot;</strong> matches the desired supportive tone by naming that exact role.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;Respond as a strict examiner who only lists errors.&quot;</b>: this persona produces harsh, one-sided feedback, the opposite of supportive.</span><span class='qd'><b>&quot;Limit the feedback to 20 words.&quot;</b>: this is a length constraint, not a persona.</span><span class='qd'><b>&quot;Here is the essay rubric.&quot;</b>: this is context, not a role.</span>" },
{ id:"D2-028", domain:2, obj:"2.2", diff:"easy", q:"Which of these is NOT a persona instruction?", options:["&quot;You are a helpful travel agent.&quot;","&quot;Act as a fitness coach.&quot;","&quot;Pretend you are a museum tour guide.&quot;","&quot;Respond in three bullet points.&quot;"], answer:3, explain:"<strong>&quot;Respond in three bullet points.&quot;</strong> is a formatting constraint, not a role, so it is not a persona instruction.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;You are a helpful travel agent.&quot;</b>: this assigns a role, which is a persona.</span><span class='qd'><b>&quot;Act as a fitness coach.&quot;</b>: this assigns a role, which is a persona.</span><span class='qd'><b>&quot;Pretend you are a museum tour guide.&quot;</b>: this assigns a role, which is a persona.</span>" },
{ id:"D2-029", domain:2, obj:"2.2", diff:"hard", q:"A user asks for legal-style contract language and gets a plain, informal answer. Which persona adjustment is MOST likely to fix the register?", options:["&quot;Act as a contracts attorney and use precise, formal legal wording.&quot;","&quot;Respond faster.&quot;","&quot;Keep it under 100 words.&quot;","&quot;Attach the contract file.&quot;"], answer:0, explain:"<strong>&quot;Act as a contracts attorney and use precise, formal legal wording.&quot;</strong> assigns the expert role whose register matches the desired formal, legal style.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;Respond faster.&quot;</b>: speed does not change the tone or register.</span><span class='qd'><b>&quot;Keep it under 100 words.&quot;</b>: a length limit does not make the wording more formal or legal.</span><span class='qd'><b>&quot;Attach the contract file.&quot;</b>: attaching a file adds context but does not set the professional voice.</span>" },
{ id:"D2-030", domain:2, obj:"2.2", diff:"hard", q:"Which scenario shows a PERSONA and a GOAL working together correctly?", options:["&quot;Keep it short. Make it formal.&quot;","&quot;Act as a UX researcher and write five user-interview questions for a banking app.&quot;","&quot;Here is our brand guide. Here is our logo.&quot;","&quot;You are helpful. You are smart.&quot;"], answer:1, explain:"<strong>&quot;Act as a UX researcher and write five user-interview questions for a banking app.&quot;</strong> pairs a clear role (UX researcher) with a specific deliverable (five interview questions).<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;Keep it short. Make it formal.&quot;</b>: these are two constraints with no persona or goal.</span><span class='qd'><b>&quot;Here is our brand guide. Here is our logo.&quot;</b>: these are two pieces of context, not a persona plus goal.</span><span class='qd'><b>&quot;You are helpful. You are smart.&quot;</b>: these are vague compliments that assign no useful role or deliverable.</span>" },
{ id:"D2-031", domain:2, obj:"2.2", diff:"easy", q:"When would specifying YOUR OWN role in the prompt help the AI most?", options:["When you want a longer answer","When you want to attach a file","When your expertise level changes how the answer should be pitched","When you want a specific word count"], answer:2, explain:"<strong>When your expertise level changes how the answer should be pitched</strong> — telling the AI you are a novice or an expert lets it match the explanation to you.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>When you want a longer answer</b>: length is controlled by a constraint, not your stated role.</span><span class='qd'><b>When you want to attach a file</b>: attaching a file is a context action, unrelated to stating your role.</span><span class='qd'><b>When you want a specific word count</b>: word count is a constraint, not a persona detail.</span>" },
{ id:"D2-032", domain:2, obj:"2.2", diff:"easy", q:"Which prompt would most likely produce a response aimed at children rather than adults?", options:["&quot;Explain gravity to a physics graduate student.&quot;","&quot;Explain gravity in a formal research tone.&quot;","&quot;Explain gravity in exactly 400 words.&quot;","&quot;Explain gravity as if speaking to a curious seven-year-old.&quot;"], answer:3, explain:"<strong>&quot;Explain gravity as if speaking to a curious seven-year-old.&quot;</strong> sets an audience-oriented persona that pushes the AI toward simple, child-friendly language.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;Explain gravity to a physics graduate student.&quot;</b>: this targets an advanced adult audience.</span><span class='qd'><b>&quot;Explain gravity in a formal research tone.&quot;</b>: this is a tone constraint aimed at adults.</span><span class='qd'><b>&quot;Explain gravity in exactly 400 words.&quot;</b>: this is a length constraint and says nothing about audience.</span>" },
{ id:"D2-033", domain:2, obj:"2.2", diff:"hard", q:"A prompt reads: &quot;You are a doctor, a lawyer, a chef, and a pilot. Answer my question about taxes.&quot; What is the likely problem with this PERSONA?", options:["Stacking many unrelated roles dilutes the relevant expertise","It is too specific to one field","It omits the goal entirely","It uses too formal a tone"], answer:0, explain:"<strong>Stacking many unrelated roles dilutes the relevant expertise</strong> — for a tax question, only a finance/tax role helps, and the extra roles add noise rather than value.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It is too specific to one field</b>: the issue is the opposite; it spreads across too many fields.</span><span class='qd'><b>It omits the goal entirely</b>: the goal (answer a tax question) is actually present.</span><span class='qd'><b>It uses too formal a tone</b>: no tone is specified, so formality is not the flaw.</span>" },
{ id:"D2-034", domain:2, obj:"2.2", diff:"easy", q:"&quot;Act as a customer-service representative for our software company&quot; is an example of setting the:", options:["Goal","Persona","Constraint","Context file"], answer:1, explain:"<strong>Persona</strong> is being set, because the instruction assigns the AI a specific role to speak from.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Goal</b>: no deliverable is named, so this is not the goal.</span><span class='qd'><b>Constraint</b>: no limit on length, tone, or format is given.</span><span class='qd'><b>Context file</b>: no source material is attached.</span>" },
{ id:"D2-035", domain:2, obj:"2.2", diff:"medium", q:"A recruiter wants the AI to review a resume from a hiring manager's perspective. Which persona instruction fits best?", options:["&quot;You are the job applicant.&quot;","&quot;Keep your review under 50 words.&quot;","&quot;Act as a hiring manager evaluating this resume for a marketing role.&quot;","&quot;Here is the resume file.&quot;"], answer:2, explain:"<strong>&quot;Act as a hiring manager evaluating this resume for a marketing role.&quot;</strong> assigns the exact viewpoint the recruiter wants the AI to take.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;You are the job applicant.&quot;</b>: this is the wrong perspective for evaluating the resume.</span><span class='qd'><b>&quot;Keep your review under 50 words.&quot;</b>: this is a length constraint, not a perspective.</span><span class='qd'><b>&quot;Here is the resume file.&quot;</b>: this supplies context but sets no viewpoint.</span>" },
{ id:"D2-036", domain:2, obj:"2.2", diff:"medium", q:"Which statement about PERSONA is most accurate?", options:["A persona forces the AI to tell only the truth","A persona is required in every single prompt","A persona replaces the goal","A persona shapes style and perspective but does not make claims factually verified"], answer:3, explain:"<strong>A persona shapes style and perspective but does not make claims factually verified</strong> — it influences how the AI answers, while accuracy still depends on the model and your verification.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A persona forces the AI to tell only the truth</b>: a role cannot guarantee truthfulness.</span><span class='qd'><b>A persona is required in every single prompt</b>: personas are helpful but optional.</span><span class='qd'><b>A persona replaces the goal</b>: a goal is still needed even when a persona is set.</span>" },
{ id:"D2-037", domain:2, obj:"2.2", diff:"hard", q:"You want beginner-friendly cooking guidance. Which combined persona statement is strongest?", options:["&quot;Act as a patient cooking instructor, and treat me as someone who has never cooked before.&quot;","&quot;You are a chef.&quot;","&quot;I am a professional chef.&quot;","&quot;Respond in French.&quot;"], answer:0, explain:"<strong>&quot;Act as a patient cooking instructor, and treat me as someone who has never cooked before.&quot;</strong> sets both the AI's role and your own beginner level, aligning the whole answer to your needs.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;You are a chef.&quot;</b>: this sets a role but says nothing about your beginner level, so the answer may be too advanced.</span><span class='qd'><b>&quot;I am a professional chef.&quot;</b>: claiming professional expertise would make the AI skip beginner explanations.</span><span class='qd'><b>&quot;Respond in French.&quot;</b>: this is a language constraint unrelated to the beginner persona.</span>" },
{ id:"D2-038", domain:2, obj:"2.2", diff:"medium", q:"Which persona choice best fits the goal &quot;write a lighthearted birthday message&quot;?", options:["&quot;Act as a somber funeral director.&quot;","&quot;Act as a cheerful, witty friend.&quot;","&quot;Act as a tax auditor.&quot;","&quot;Act as a technical support agent.&quot;"], answer:1, explain:"<strong>&quot;Act as a cheerful, witty friend.&quot;</strong> matches the lighthearted, celebratory tone the birthday message needs.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;Act as a somber funeral director.&quot;</b>: a somber role clashes with a celebratory message.</span><span class='qd'><b>&quot;Act as a tax auditor.&quot;</b>: an auditor's dry, formal voice is a poor fit for a birthday note.</span><span class='qd'><b>&quot;Act as a technical support agent.&quot;</b>: a support-agent tone is procedural, not festive.</span>" },
{ id:"D2-039", domain:2, obj:"2.2", diff:"hard", q:"A prompt already has a clear goal and constraints but produces answers that feel generic. Which addition targets that specific weakness?", options:["Repeat the goal twice","Reduce the word limit","Assign a relevant expert persona to give the answer a focused perspective","Change the file format"], answer:2, explain:"<strong>Assign a relevant expert persona to give the answer a focused perspective</strong> — a fitting role adds depth and viewpoint that a bare goal-plus-constraints prompt often lacks.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Repeat the goal twice</b>: repetition adds no new perspective and does not reduce generic output.</span><span class='qd'><b>Reduce the word limit</b>: a shorter answer can still be generic.</span><span class='qd'><b>Change the file format</b>: format has no effect on how focused the perspective is.</span>" },
{ id:"D2-040", domain:2, obj:"2.2", diff:"medium", q:"Which is the clearest example of stating both the AI's role AND the user's role in one prompt?", options:["&quot;Summarize this in five bullets.&quot;","&quot;Here is my W-2 form.&quot;","&quot;Use a formal tone throughout.&quot;","&quot;You are a tax advisor; I am a freelancer filing taxes for the first time.&quot;"], answer:3, explain:"<strong>&quot;You are a tax advisor; I am a freelancer filing taxes for the first time.&quot;</strong> defines the AI's expertise and the user's situation together, which is a complete persona.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;Summarize this in five bullets.&quot;</b>: this is a goal plus a format constraint.</span><span class='qd'><b>&quot;Here is my W-2 form.&quot;</b>: this is context, not a statement of roles.</span><span class='qd'><b>&quot;Use a formal tone throughout.&quot;</b>: this is a tone constraint.</span>" },

/* ===================== Objective 2.3 - The CONTEXT building block ===================== */
{ id:"D2-041", domain:2, obj:"2.3", diff:"easy", q:"Which building block gives the AI the background and situation it needs to respond appropriately?", options:["Context","Goal","Persona","Constraint"], answer:0, explain:"<strong>Context</strong> supplies the background, situation, and relevant details the AI needs to produce a fitting response.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Goal</b>: the goal names the deliverable, not the background.</span><span class='qd'><b>Persona</b>: the persona sets the role, not the situational details.</span><span class='qd'><b>Constraint</b>: a constraint limits the output rather than providing background.</span>" },
{ id:"D2-042", domain:2, obj:"2.3", diff:"easy", q:"Which addition provides CONTEXT to a prompt asking the AI to write an apology email?", options:["&quot;Keep it under 150 words.&quot;","&quot;The customer's order arrived two weeks late and was damaged.&quot;","&quot;Act as a support agent.&quot;","&quot;Write an apology email.&quot;"], answer:1, explain:"<strong>&quot;The customer's order arrived two weeks late and was damaged.&quot;</strong> describes the situation so the AI can write a relevant, specific apology.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;Keep it under 150 words.&quot;</b>: this is a length constraint.</span><span class='qd'><b>&quot;Act as a support agent.&quot;</b>: this is a persona.</span><span class='qd'><b>&quot;Write an apology email.&quot;</b>: this is the goal, not the background.</span>" },
{ id:"D2-043", domain:2, obj:"2.3", diff:"easy", q:"Why does providing CONTEXT usually lead to a better AI response?", options:["It shortens the answer","It sets the AI's word count","It gives the AI relevant details so the answer fits your actual situation","It assigns the AI a role"], answer:2, explain:"<strong>It gives the AI relevant details so the answer fits your actual situation</strong> — without background, the AI must guess, and guesses are often off-target.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It shortens the answer</b>: context often adds detail rather than shortening output.</span><span class='qd'><b>It sets the AI's word count</b>: word count is a constraint, not context.</span><span class='qd'><b>It assigns the AI a role</b>: assigning a role is the persona building block.</span>" },
{ id:"D2-044", domain:2, obj:"2.3", diff:"medium", q:"A user asks the AI to plan a team lunch but gives no CONTEXT. Which detail would most help the AI?", options:["&quot;Respond in a friendly tone.&quot;","&quot;You are an event planner.&quot;","&quot;Make it a good plan.&quot;","&quot;The team has eight people, two are vegetarian, and the budget is $150.&quot;"], answer:3, explain:"<strong>&quot;The team has eight people, two are vegetarian, and the budget is $150.&quot;</strong> supplies the situational facts the AI needs to plan a realistic, fitting lunch.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;Respond in a friendly tone.&quot;</b>: this is a tone constraint, not situational detail.</span><span class='qd'><b>&quot;You are an event planner.&quot;</b>: this is a persona.</span><span class='qd'><b>&quot;Make it a good plan.&quot;</b>: &quot;good&quot; is vague and adds no facts.</span>" },
{ id:"D2-045", domain:2, obj:"2.3", diff:"easy", q:"Which prompt includes the MOST useful CONTEXT for drafting a follow-up sales email?", options:["&quot;Write a follow-up email to a prospect who demoed our software last week but had concerns about price.&quot;","&quot;Write a follow-up email.&quot;","&quot;Write a follow-up email in a formal tone.&quot;","&quot;You are a salesperson writing a follow-up email.&quot;"], answer:0, explain:"<strong>&quot;Write a follow-up email to a prospect who demoed our software last week but had concerns about price.&quot;</strong> gives the AI the timing and the specific objection, so it can address them directly.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;Write a follow-up email.&quot;</b>: this is a bare goal with no situational detail.</span><span class='qd'><b>&quot;Write a follow-up email in a formal tone.&quot;</b>: this adds a tone constraint but no background about the prospect.</span><span class='qd'><b>&quot;You are a salesperson writing a follow-up email.&quot;</b>: this adds a persona but still no situational facts.</span>" },
{ id:"D2-046", domain:2, obj:"2.3", diff:"medium", q:"A lesson-planning prompt says: &quot;Plan a math lesson.&quot; Which piece of CONTEXT would sharpen it most?", options:["&quot;Respond in bullet points.&quot;","&quot;It is for a 45-minute class of 25 third-graders learning fractions for the first time.&quot;","&quot;You are a teacher.&quot;","&quot;Keep it engaging.&quot;"], answer:1, explain:"<strong>&quot;It is for a 45-minute class of 25 third-graders learning fractions for the first time.&quot;</strong> supplies the grade, class size, duration, and topic — the situational facts a good lesson plan requires.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;Respond in bullet points.&quot;</b>: this is a format constraint.</span><span class='qd'><b>&quot;You are a teacher.&quot;</b>: this is a persona.</span><span class='qd'><b>&quot;Keep it engaging.&quot;</b>: this is a vague quality request, not concrete context.</span>" },
{ id:"D2-047", domain:2, obj:"2.3", diff:"easy", q:"Which of the following is an example of CONTEXT rather than a constraint?", options:["&quot;Limit the reply to three sentences.&quot;","&quot;Use a professional tone.&quot;","&quot;Our nonprofit serves elderly residents in rural areas.&quot;","&quot;Return the answer as a table.&quot;"], answer:2, explain:"<strong>&quot;Our nonprofit serves elderly residents in rural areas.&quot;</strong> describes the organization's situation, which is background context.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;Limit the reply to three sentences.&quot;</b>: this is a length constraint.</span><span class='qd'><b>&quot;Use a professional tone.&quot;</b>: this is a tone constraint.</span><span class='qd'><b>&quot;Return the answer as a table.&quot;</b>: this is a format constraint.</span>" },
{ id:"D2-048", domain:2, obj:"2.3", diff:"medium", q:"A prompt to write a cover letter includes the job title and the applicant's two most relevant achievements. Those achievements function as:", options:["The goal","A persona","A constraint on length","Context the AI uses to tailor the letter"], answer:3, explain:"<strong>Context the AI uses to tailor the letter</strong> — the achievements are background facts the AI weaves into a personalized cover letter.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The goal</b>: the goal is to write the cover letter; the achievements are supporting detail.</span><span class='qd'><b>A persona</b>: a persona is a role, not a list of accomplishments.</span><span class='qd'><b>A constraint on length</b>: the achievements say nothing about length.</span>" },
{ id:"D2-049", domain:2, obj:"2.3", diff:"hard", q:"An employee asks the AI to &quot;summarize the project status for leadership&quot; but provides no project details. What is the core weakness?", options:["There is no context, so the AI has nothing real to summarize","The persona is wrong","The tone is too casual","The word count is unspecified"], answer:0, explain:"<strong>There is no context, so the AI has nothing real to summarize</strong> — without the actual project facts, the model can only invent a generic or fabricated status.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The persona is wrong</b>: no persona is set, so it cannot be wrong.</span><span class='qd'><b>The tone is too casual</b>: no tone is specified, and tone is not the missing essential here.</span><span class='qd'><b>The word count is unspecified</b>: an unspecified length is minor compared with having no source content at all.</span>" },
{ id:"D2-050", domain:2, obj:"2.3", diff:"hard", q:"Which prompt gives the AI enough CONTEXT to write a relevant customer FAQ answer?", options:["&quot;Answer a customer question.&quot;","&quot;A customer asks whether our subscription can be paused; our plan allows one 30-day pause per year. Write the answer.&quot;","&quot;You are a support agent answering questions.&quot;","&quot;Keep the answer short and polite.&quot;"], answer:1, explain:"<strong>&quot;A customer asks whether our subscription can be paused; our plan allows one 30-day pause per year. Write the answer.&quot;</strong> supplies the exact question and the policy fact, so the AI can respond accurately.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;Answer a customer question.&quot;</b>: this names no question and no policy.</span><span class='qd'><b>&quot;You are a support agent answering questions.&quot;</b>: this is a persona with no situational facts.</span><span class='qd'><b>&quot;Keep the answer short and polite.&quot;</b>: this is a tone/length constraint without the needed information.</span>" },
{ id:"D2-051", domain:2, obj:"2.3", diff:"easy", q:"You ask the AI to recommend a laptop. Which CONTEXT most improves the recommendation?", options:["&quot;You are a tech reviewer.&quot;","&quot;Answer in under 100 words.&quot;","&quot;I need it for video editing, my budget is $1,200, and I prefer a lightweight model.&quot;","&quot;Recommend a laptop.&quot;"], answer:2, explain:"<strong>&quot;I need it for video editing, my budget is $1,200, and I prefer a lightweight model.&quot;</strong> gives the use case, budget, and preference the AI needs to make a fitting recommendation.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;You are a tech reviewer.&quot;</b>: this is a persona, not situational detail.</span><span class='qd'><b>&quot;Answer in under 100 words.&quot;</b>: this is a length constraint.</span><span class='qd'><b>&quot;Recommend a laptop.&quot;</b>: this is the goal without any qualifying facts.</span>" },
{ id:"D2-052", domain:2, obj:"2.3", diff:"medium", q:"Which statement best explains the risk of giving the AI too little CONTEXT?", options:["The AI will refuse to answer","The AI will always ask for a persona","The AI will shorten the answer automatically","The AI may produce a generic or inaccurate response based on assumptions"], answer:3, explain:"<strong>The AI may produce a generic or inaccurate response based on assumptions</strong> — with sparse background, the model fills gaps with guesses that may not match your reality.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The AI will refuse to answer</b>: it usually answers anyway, just less accurately.</span><span class='qd'><b>The AI will always ask for a persona</b>: it does not require a persona to respond.</span><span class='qd'><b>The AI will shorten the answer automatically</b>: missing context does not automatically shorten output.</span>" },
{ id:"D2-053", domain:2, obj:"2.3", diff:"hard", q:"A prompt supplies the audience, the purpose, and the key facts of a situation, but no deliverable is named. Which building block is still MISSING?", options:["Goal","Context","Persona","Constraint"], answer:0, explain:"<strong>Goal</strong> is missing because the prompt provides rich context but never says what the AI should actually produce.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Context</b>: audience, purpose, and key facts are context, which is present.</span><span class='qd'><b>Persona</b>: a missing persona is optional; the essential gap is the undefined deliverable.</span><span class='qd'><b>Constraint</b>: constraints are optional refinements, not the missing core element here.</span>" },
{ id:"D2-054", domain:2, obj:"2.3", diff:"easy", q:"&quot;Our store is having a clearance sale this weekend and we want to attract families&quot; is which building block?", options:["Goal","Context","Constraint","Persona"], answer:1, explain:"<strong>Context</strong> is being provided, because the sentence describes the situation and audience the AI should account for.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Goal</b>: no deliverable is requested here.</span><span class='qd'><b>Constraint</b>: no limit on length, format, or tone is set.</span><span class='qd'><b>Persona</b>: no role is assigned to the AI.</span>" },
{ id:"D2-055", domain:2, obj:"2.3", diff:"medium", q:"A user wants the AI to reply to a specific email but only describes it vaguely. What is the best way to supply accurate CONTEXT?", options:["Tell the AI to imagine what the email said","Ask the AI to write faster","Paste the actual email text into the prompt","Set a strict word limit"], answer:2, explain:"<strong>Paste the actual email text into the prompt</strong> gives the AI the real content, so its reply responds to what was truly written rather than a guess.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Tell the AI to imagine what the email said</b>: imagining invites fabrication and an off-target reply.</span><span class='qd'><b>Ask the AI to write faster</b>: speed does not supply the missing content.</span><span class='qd'><b>Set a strict word limit</b>: a word limit is a constraint and provides no context.</span>" },
{ id:"D2-056", domain:2, obj:"2.3", diff:"medium", q:"Which prompt best demonstrates supplying CONTEXT before stating the goal?", options:["&quot;Write it in 200 words. Write a memo.&quot;","&quot;You are an HR manager. You are helpful.&quot;","&quot;Make the memo professional and short.&quot;","&quot;We are launching a new remote-work policy next month. Write a memo announcing it to staff.&quot;"], answer:3, explain:"<strong>&quot;We are launching a new remote-work policy next month. Write a memo announcing it to staff.&quot;</strong> first sets the situation and then states the deliverable, a clean context-then-goal structure.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;Write it in 200 words. Write a memo.&quot;</b>: this pairs a constraint with a bare goal and includes no context.</span><span class='qd'><b>&quot;You are an HR manager. You are helpful.&quot;</b>: this is a persona plus a vague compliment, not context and goal.</span><span class='qd'><b>&quot;Make the memo professional and short.&quot;</b>: these are two constraints without any situational background.</span>" },
{ id:"D2-057", domain:2, obj:"2.3", diff:"hard", q:"A prompt about writing a grant proposal includes the funder's stated priorities. Why is including those priorities valuable CONTEXT?", options:["It lets the AI align the proposal with what the funder actually cares about","It shortens the proposal","It sets the AI's persona","It forces a specific word count"], answer:0, explain:"<strong>It lets the AI align the proposal with what the funder actually cares about</strong> — knowing the funder's priorities is background that shapes a more persuasive, relevant proposal.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It shortens the proposal</b>: adding priorities does not shorten it and often adds detail.</span><span class='qd'><b>It sets the AI's persona</b>: priorities are situational facts, not a role.</span><span class='qd'><b>It forces a specific word count</b>: priorities have nothing to do with length limits.</span>" },
{ id:"D2-058", domain:2, obj:"2.3", diff:"medium", q:"Which of these prompts would benefit MOST from adding CONTEXT?", options:["&quot;Define the word 'photosynthesis'.&quot;","&quot;Reply to my coworker's message.&quot;","&quot;What is 12 times 12?&quot;","&quot;List the days of the week.&quot;"], answer:1, explain:"<strong>&quot;Reply to my coworker's message.&quot;</strong> needs context most, because the AI cannot craft a good reply without knowing what the message said.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;Define the word 'photosynthesis'.&quot;</b>: this is a self-contained factual request needing no personal context.</span><span class='qd'><b>&quot;What is 12 times 12?&quot;</b>: this is a fixed calculation with a single answer.</span><span class='qd'><b>&quot;List the days of the week.&quot;</b>: this is universal knowledge requiring no situational detail.</span>" },
{ id:"D2-059", domain:2, obj:"2.3", diff:"hard", q:"A manager pastes a long, unrelated company history into a prompt asking for a two-line meeting reminder. What CONTEXT problem does this show?", options:["Too little context","A missing persona","Irrelevant or excessive context that buries the actual need","A missing constraint"], answer:2, explain:"<strong>Irrelevant or excessive context that buries the actual need</strong> — dumping unrelated history distracts the AI from the simple reminder and can degrade the result.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Too little context</b>: the issue is too much, not too little.</span><span class='qd'><b>A missing persona</b>: the reminder task does not hinge on a persona.</span><span class='qd'><b>A missing constraint</b>: the two-line request already implies the needed limit.</span>" },
{ id:"D2-060", domain:2, obj:"2.3", diff:"medium", q:"Which prompt element is CONTEXT: &quot;The recipient is my manager, whom I have never emailed before&quot;?", options:["It is the goal of the email","It is a formatting constraint","It is the AI's persona","It is context about the relationship that helps set the right approach"], answer:3, explain:"<strong>It is context about the relationship that helps set the right approach</strong> — knowing the recipient is an unfamiliar manager guides tone and formality.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It is the goal of the email</b>: it describes the recipient, not the deliverable.</span><span class='qd'><b>It is a formatting constraint</b>: it says nothing about format or length.</span><span class='qd'><b>It is the AI's persona</b>: it describes your recipient, not a role the AI adopts.</span>" },

/* ===================== Objective 2.4 - CONSTRAINTS & contextual files ===================== */
{ id:"D2-061", domain:2, obj:"2.4", diff:"easy", q:"Which building block sets limits such as length, tone, format, or what to avoid?", options:["Constraints","Goal","Persona","Context"], answer:0, explain:"<strong>Constraints</strong> are the limits you place on the output, such as word count, tone, format, or content to include or exclude.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Goal</b>: the goal is the outcome, not the limits on it.</span><span class='qd'><b>Persona</b>: the persona is the role, not a limit.</span><span class='qd'><b>Context</b>: context is background, not a boundary on the output.</span>" },
{ id:"D2-062", domain:2, obj:"2.4", diff:"easy", q:"&quot;Keep the summary to three sentences&quot; is an example of which constraint type?", options:["Tone constraint","Length constraint","Format constraint","Persona"], answer:1, explain:"<strong>Length constraint</strong> limits how long the output can be, and &quot;three sentences&quot; caps the length.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Tone constraint</b>: tone would specify style such as formal or casual, not length.</span><span class='qd'><b>Format constraint</b>: format would specify a structure such as a table or bullets.</span><span class='qd'><b>Persona</b>: a persona assigns a role, not a length limit.</span>" },
{ id:"D2-063", domain:2, obj:"2.4", diff:"easy", q:"&quot;Write in a formal, professional tone&quot; is which constraint type?", options:["Length constraint","Format constraint","Tone constraint","Goal"], answer:2, explain:"<strong>Tone constraint</strong> controls the style or voice of the output, and &quot;formal, professional&quot; sets that voice.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Length constraint</b>: this limits size, not style.</span><span class='qd'><b>Format constraint</b>: this specifies structure, not tone.</span><span class='qd'><b>Goal</b>: the goal is the deliverable, not the tone.</span>" },
{ id:"D2-064", domain:2, obj:"2.4", diff:"medium", q:"&quot;Present the answer as a numbered list&quot; is which constraint type?", options:["Tone constraint","Persona","Context","Format constraint"], answer:3, explain:"<strong>Format constraint</strong> dictates the structure of the output, and a numbered list is a specific format.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Tone constraint</b>: tone concerns style, not structure.</span><span class='qd'><b>Persona</b>: a persona is a role, not a format.</span><span class='qd'><b>Context</b>: context is background, not a structural rule.</span>" },
{ id:"D2-065", domain:2, obj:"2.4", diff:"medium", q:"Which instruction is a constraint about what to AVOID?", options:["&quot;Do not mention pricing in the reply.&quot;","&quot;Include our refund policy.&quot;","&quot;Act as a support agent.&quot;","&quot;The customer is upset.&quot;"], answer:0, explain:"<strong>&quot;Do not mention pricing in the reply.&quot;</strong> is an exclusion constraint that tells the AI what to leave out.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;Include our refund policy.&quot;</b>: this is an inclusion constraint, the opposite of avoiding something.</span><span class='qd'><b>&quot;Act as a support agent.&quot;</b>: this is a persona.</span><span class='qd'><b>&quot;The customer is upset.&quot;</b>: this is context.</span>" },
{ id:"D2-066", domain:2, obj:"2.4", diff:"medium", q:"A user wants an AI summary of a specific 12-page report they have. What is the BEST way to make sure the AI works from the real content?", options:["Describe the report from memory","Attach the report as a contextual file","Tell the AI to search its training data","Ask the AI to guess the contents"], answer:1, explain:"<strong>Attach the report as a contextual file</strong> so the AI reads the actual source material and summarizes what the document truly says.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Describe the report from memory</b>: a vague recollection omits details and risks errors.</span><span class='qd'><b>Tell the AI to search its training data</b>: the AI cannot retrieve your private report from training data.</span><span class='qd'><b>Ask the AI to guess the contents</b>: guessing invites fabrication rather than a faithful summary.</span>" },
{ id:"D2-067", domain:2, obj:"2.4", diff:"easy", q:"What is a &quot;contextual file&quot; in prompt engineering?", options:["A file that limits the response length","The AI's saved persona","A relevant document or data you attach so the AI can use its actual content","A list of tone options"], answer:2, explain:"<strong>A relevant document or data you attach so the AI can use its actual content</strong> defines a contextual file, which grounds the response in real source material.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A file that limits the response length</b>: files provide content; length is set by a constraint you write.</span><span class='qd'><b>The AI's saved persona</b>: a persona is a role in the prompt, not an attached file.</span><span class='qd'><b>A list of tone options</b>: tone options are constraints, not a source document.</span>" },
{ id:"D2-068", domain:2, obj:"2.4", diff:"medium", q:"Which is the strongest reason to attach a contextual file instead of pasting a short description?", options:["It makes the prompt shorter","It changes the AI's tone","It assigns the AI a persona","It gives the AI the precise, complete source material to work from"], answer:3, explain:"<strong>It gives the AI the precise, complete source material to work from</strong>, reducing guessing and improving accuracy compared with a brief paraphrase.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It makes the prompt shorter</b>: attaching a full document usually adds material, not brevity.</span><span class='qd'><b>It changes the AI's tone</b>: tone is set by constraints, not by attaching a file.</span><span class='qd'><b>It assigns the AI a persona</b>: a file provides content, not a role.</span>" },
{ id:"D2-069", domain:2, obj:"2.4", diff:"hard", q:"A user attaches ten unrelated PDFs and asks a question that concerns only one of them. What contextual-file problem does this create?", options:["Irrelevant attachments that dilute focus and can confuse the response","Too little source material","A missing goal","A missing persona"], answer:0, explain:"<strong>Irrelevant attachments that dilute focus and can confuse the response</strong> — supplying nine unrelated files forces the AI to sift noise and can degrade the answer.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Too little source material</b>: the problem is too much and unfocused, not too little.</span><span class='qd'><b>A missing goal</b>: a question is asked, so a goal exists.</span><span class='qd'><b>A missing persona</b>: the issue is attachment relevance, not a missing role.</span>" },
{ id:"D2-070", domain:2, obj:"2.4", diff:"medium", q:"Which set of constraints is well matched to the goal &quot;write a professional out-of-office reply&quot;?", options:["&quot;Make it 2,000 words and very casual.&quot;","&quot;Keep it to three or four sentences, polite and professional, and include a return date.&quot;","&quot;Use slang and emojis throughout.&quot;","&quot;Write it as a long poem.&quot;"], answer:1, explain:"<strong>&quot;Keep it to three or four sentences, polite and professional, and include a return date.&quot;</strong> sets sensible length, tone, and inclusion limits that fit an out-of-office reply.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;Make it 2,000 words and very casual.&quot;</b>: this is far too long and too casual for the purpose.</span><span class='qd'><b>&quot;Use slang and emojis throughout.&quot;</b>: slang and emojis conflict with a professional reply.</span><span class='qd'><b>&quot;Write it as a long poem.&quot;</b>: a poem is an inappropriate format for an out-of-office message.</span>" },
{ id:"D2-071", domain:2, obj:"2.4", diff:"easy", q:"Which constraint would help ensure an AI-written recipe is easy to follow?", options:["&quot;You are a chef.&quot;","&quot;This is for a dinner party.&quot;","&quot;List ingredients first, then numbered steps.&quot;","&quot;Make it delicious.&quot;"], answer:2, explain:"<strong>&quot;List ingredients first, then numbered steps.&quot;</strong> is a format constraint that structures the recipe for easy following.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;You are a chef.&quot;</b>: this is a persona, not a structural rule.</span><span class='qd'><b>&quot;This is for a dinner party.&quot;</b>: this is context, not a format.</span><span class='qd'><b>&quot;Make it delicious.&quot;</b>: this is a vague quality wish, not a constraint on structure.</span>" },
{ id:"D2-072", domain:2, obj:"2.4", diff:"hard", q:"A prompt asks for a 100-word summary but also says &quot;explain every detail thoroughly.&quot; What is the issue with these constraints?", options:["They are perfectly compatible","There are no constraints present","One of them is a persona","They conflict: 100 words cannot hold an exhaustive, thorough explanation"], answer:3, explain:"<strong>They conflict: 100 words cannot hold an exhaustive, thorough explanation</strong> — a tight word cap and a demand for full detail pull in opposite directions and confuse the AI.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>They are perfectly compatible</b>: they are not, since brevity and exhaustiveness contradict each other.</span><span class='qd'><b>There are no constraints present</b>: both a length limit and a detail demand are constraints.</span><span class='qd'><b>One of them is a persona</b>: neither instruction assigns a role.</span>" },
{ id:"D2-073", domain:2, obj:"2.4", diff:"medium", q:"Which instruction is an INCLUSION constraint (something that must appear)?", options:["&quot;Be sure to mention the 30-day money-back guarantee.&quot;","&quot;Do not use technical jargon.&quot;","&quot;Act as a copywriter.&quot;","&quot;The product launches Friday.&quot;"], answer:0, explain:"<strong>&quot;Be sure to mention the 30-day money-back guarantee.&quot;</strong> requires a specific element to be present, which is an inclusion constraint.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;Do not use technical jargon.&quot;</b>: this is an exclusion constraint, telling the AI what to avoid.</span><span class='qd'><b>&quot;Act as a copywriter.&quot;</b>: this is a persona.</span><span class='qd'><b>&quot;The product launches Friday.&quot;</b>: this is context.</span>" },
{ id:"D2-074", domain:2, obj:"2.4", diff:"easy", q:"Which is a FORMAT constraint?", options:["&quot;Use a warm, friendly tone.&quot;","&quot;Return the results in a two-column table.&quot;","&quot;Our audience is teenagers.&quot;","&quot;Write a summary.&quot;"], answer:1, explain:"<strong>&quot;Return the results in a two-column table.&quot;</strong> specifies the structure of the output, which is a format constraint.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;Use a warm, friendly tone.&quot;</b>: this is a tone constraint.</span><span class='qd'><b>&quot;Our audience is teenagers.&quot;</b>: this is context.</span><span class='qd'><b>&quot;Write a summary.&quot;</b>: this is the goal.</span>" },
{ id:"D2-075", domain:2, obj:"2.4", diff:"hard", q:"A user attaches a company style guide as a contextual file when asking the AI to draft web copy. How does that file most help?", options:["It sets the AI's word count","It guarantees the copy is error-free","It lets the AI match the brand's required voice and terminology","It assigns the AI a legal persona"], answer:2, explain:"<strong>It lets the AI match the brand's required voice and terminology</strong> — the attached style guide gives the AI the real rules to follow, improving on-brand output.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It sets the AI's word count</b>: a style guide is source material, not a length limit.</span><span class='qd'><b>It guarantees the copy is error-free</b>: attaching a file cannot guarantee perfection.</span><span class='qd'><b>It assigns the AI a legal persona</b>: a style guide is content, not a role.</span>" },
{ id:"D2-076", domain:2, obj:"2.4", diff:"easy", q:"Which prompt uses a constraint to control the reading level of the output?", options:["&quot;Explain it however you like.&quot;","&quot;You are a scientist.&quot;","&quot;This is about climate.&quot;","&quot;Explain it using simple words a middle-schooler would understand.&quot;"], answer:3, explain:"<strong>&quot;Explain it using simple words a middle-schooler would understand.&quot;</strong> constrains vocabulary and complexity to a target reading level.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;Explain it however you like.&quot;</b>: this imposes no constraint at all.</span><span class='qd'><b>&quot;You are a scientist.&quot;</b>: this is a persona and could raise, not lower, complexity.</span><span class='qd'><b>&quot;This is about climate.&quot;</b>: this is context, not a reading-level limit.</span>" },
{ id:"D2-077", domain:2, obj:"2.4", diff:"medium", q:"Why should constraints be realistic and non-contradictory?", options:["So the AI can satisfy all of them without conflict, producing a coherent result","So the AI writes faster","So the prompt needs no goal","So the AI can ignore the context"], answer:0, explain:"<strong>So the AI can satisfy all of them without conflict, producing a coherent result</strong> — contradictory limits force the AI to violate one, yielding an inconsistent output.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>So the AI writes faster</b>: consistency affects quality, not speed.</span><span class='qd'><b>So the prompt needs no goal</b>: constraints never remove the need for a goal.</span><span class='qd'><b>So the AI can ignore the context</b>: good constraints work with context, not against it.</span>" },
{ id:"D2-078", domain:2, obj:"2.4", diff:"hard", q:"A user asks the AI to analyze &quot;last quarter's numbers&quot; but pastes nothing and attaches nothing. Which fix directly addresses the contextual-file gap?", options:["Add a friendlier tone","Attach or paste the actual quarterly figures the analysis should use","Assign an accountant persona","Shorten the requested output"], answer:1, explain:"<strong>Attach or paste the actual quarterly figures the analysis should use</strong> gives the AI real data instead of forcing it to invent numbers.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Add a friendlier tone</b>: tone does not supply the missing data.</span><span class='qd'><b>Assign an accountant persona</b>: a persona cannot conjure the actual figures.</span><span class='qd'><b>Shorten the requested output</b>: length changes nothing about the absent source data.</span>" },
{ id:"D2-079", domain:2, obj:"2.4", diff:"medium", q:"Which of these is a constraint rather than context or a goal?", options:["&quot;Our clients are in healthcare.&quot;","&quot;Draft a newsletter blurb.&quot;","&quot;Avoid medical claims and keep it under 250 words.&quot;","&quot;You are a health writer.&quot;"], answer:2, explain:"<strong>&quot;Avoid medical claims and keep it under 250 words.&quot;</strong> combines an exclusion rule and a length limit, both of which are constraints.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;Our clients are in healthcare.&quot;</b>: this is context.</span><span class='qd'><b>&quot;Draft a newsletter blurb.&quot;</b>: this is the goal.</span><span class='qd'><b>&quot;You are a health writer.&quot;</b>: this is a persona.</span>" },
{ id:"D2-080", domain:2, obj:"2.4", diff:"hard", q:"A team lead wants the AI to base a summary strictly on an attached policy and not add outside information. Which constraint best enforces that?", options:["&quot;Make the summary engaging.&quot;","&quot;You are a policy expert.&quot;","&quot;Keep it professional.&quot;","&quot;Summarize only what is in the attached policy; do not add information from outside it.&quot;"], answer:3, explain:"<strong>&quot;Summarize only what is in the attached policy; do not add information from outside it.&quot;</strong> explicitly limits the AI to the contextual file, preventing outside additions.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;Make the summary engaging.&quot;</b>: this is a vague style wish that does not confine the source.</span><span class='qd'><b>&quot;You are a policy expert.&quot;</b>: a persona does not restrict the information source.</span><span class='qd'><b>&quot;Keep it professional.&quot;</b>: a tone constraint does not stop the AI from adding outside facts.</span>" },

/* ===================== Objective 2.5 - Right-sizing & assembling a complete prompt ===================== */
{ id:"D2-081", domain:2, obj:"2.5", diff:"easy", q:"A complete, effective prompt typically combines which building blocks?", options:["Goal, persona, context, and constraints as needed","Only a goal","Only constraints","Only a persona and a file"], answer:0, explain:"<strong>Goal, persona, context, and constraints as needed</strong> — a strong prompt assembles these building blocks so the AI has the outcome, role, background, and limits it needs.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Only a goal</b>: a bare goal often lacks the context and limits that produce a great result.</span><span class='qd'><b>Only constraints</b>: constraints alone give no outcome to aim for.</span><span class='qd'><b>Only a persona and a file</b>: without a goal, the AI has no defined deliverable.</span>" },
{ id:"D2-082", domain:2, obj:"2.5", diff:"easy", q:"What does &quot;right-sizing&quot; a prompt mean?", options:["Making every prompt as long as possible","Providing enough detail to guide the AI without overwhelming it with irrelevant information","Always using the fewest words possible","Attaching as many files as you can"], answer:1, explain:"<strong>Providing enough detail to guide the AI without overwhelming it with irrelevant information</strong> is right-sizing — the balance between too little and too much.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Making every prompt as long as possible</b>: excessive length adds noise and can hurt results.</span><span class='qd'><b>Always using the fewest words possible</b>: too little detail leaves the AI guessing.</span><span class='qd'><b>Attaching as many files as you can</b>: irrelevant attachments dilute focus rather than help.</span>" },
{ id:"D2-083", domain:2, obj:"2.5", diff:"medium", q:"Which prompt is the MOST complete for drafting a customer thank-you email?", options:["&quot;Write a thank-you email.&quot;","&quot;You are nice. Say thanks.&quot;","&quot;Act as a friendly account manager. A customer just renewed their annual plan. Write a warm 3-4 sentence thank-you email that mentions their loyalty and invites questions.&quot;","&quot;Thank-you emails are important; keep it short.&quot;"], answer:2, explain:"<strong>&quot;Act as a friendly account manager. A customer just renewed their annual plan. Write a warm 3-4 sentence thank-you email that mentions their loyalty and invites questions.&quot;</strong> includes persona, context, goal, and constraints together.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;Write a thank-you email.&quot;</b>: this is only a bare goal.</span><span class='qd'><b>&quot;You are nice. Say thanks.&quot;</b>: this is a vague persona plus a vague goal with no context or limits.</span><span class='qd'><b>&quot;Thank-you emails are important; keep it short.&quot;</b>: this is filler plus one constraint, with no real goal or context.</span>" },
{ id:"D2-084", domain:2, obj:"2.5", diff:"medium", q:"You gave the AI a huge, detailed prompt but got a confused, unfocused answer. What is a likely cause?", options:["The prompt had a clear single goal","The prompt used a persona","The prompt named the audience","The prompt was overloaded with irrelevant detail, obscuring the real request"], answer:3, explain:"<strong>The prompt was overloaded with irrelevant detail, obscuring the real request</strong> — too much noise can bury the goal and dilute the AI's focus.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The prompt had a clear single goal</b>: a clear goal would improve, not confuse, the answer.</span><span class='qd'><b>The prompt used a persona</b>: a persona alone does not cause confusion.</span><span class='qd'><b>The prompt named the audience</b>: naming the audience helps rather than harms.</span>" },
{ id:"D2-085", domain:2, obj:"2.5", diff:"medium", q:"Which prompt shows the BEST balance of detail (right-sizing) for a simple task: converting Celsius to Fahrenheit?", options:["&quot;Convert 25 C to Fahrenheit.&quot;","&quot;Act as a thermodynamics professor with 20 years of experience, consider global climate history, and convert 25 C to Fahrenheit.&quot;","&quot;Tell me about temperature.&quot;","&quot;Here are ten physics textbooks; convert 25 C to Fahrenheit.&quot;"], answer:0, explain:"<strong>&quot;Convert 25 C to Fahrenheit.&quot;</strong> is right-sized: a simple, well-defined task needs only a clear goal, not extra persona, context, or attachments.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;Act as a thermodynamics professor with 20 years of experience, consider global climate history, and convert 25 C to Fahrenheit.&quot;</b>: this over-engineers a trivial calculation with useless detail.</span><span class='qd'><b>&quot;Tell me about temperature.&quot;</b>: this is too vague and does not request the conversion.</span><span class='qd'><b>&quot;Here are ten physics textbooks; convert 25 C to Fahrenheit.&quot;</b>: attaching textbooks for a one-line conversion is needless overload.</span>" },
{ id:"D2-086", domain:2, obj:"2.5", diff:"hard", q:"A vague prompt reads: &quot;Write about our event.&quot; Which single revision adds the MOST value first?", options:["Add an emoji","Add a goal, a bit of context, and one or two constraints (for example, 'Write a 150-word invitation for our June 5 charity gala for local donors')","Attach five unrelated files","Repeat the phrase &quot;our event&quot; three times"], answer:1, explain:"<strong>Add a goal, a bit of context, and one or two constraints</strong> — combining what to produce, key situational facts, and sensible limits transforms a vague ask into an actionable prompt.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Add an emoji</b>: an emoji does not clarify the request.</span><span class='qd'><b>Attach five unrelated files</b>: irrelevant files add noise rather than value.</span><span class='qd'><b>Repeat the phrase &quot;our event&quot; three times</b>: repetition adds no new information.</span>" },
{ id:"D2-087", domain:2, obj:"2.5", diff:"medium", q:"Which is the best order for assembling a clear prompt?", options:["Constraints, then nothing else","Only the goal, repeated","Persona/role, context/background, goal/task, and constraints","Random details in any order"], answer:2, explain:"<strong>Persona/role, context/background, goal/task, and constraints</strong> is a clean, logical structure that gives the AI the role, the situation, the task, and the limits in a coherent flow.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Constraints, then nothing else</b>: limits without a goal leave nothing to produce.</span><span class='qd'><b>Only the goal, repeated</b>: repeating the goal adds no persona, context, or constraints.</span><span class='qd'><b>Random details in any order</b>: disorganized prompts are harder for the AI to follow.</span>" },
{ id:"D2-088", domain:2, obj:"2.5", diff:"hard", q:"A prompt has a clear goal, persona, and constraints, but the AI still asks &quot;What are you referring to?&quot; Which building block was most likely missing?", options:["Goal","Constraints","Persona","Context"], answer:3, explain:"<strong>Context</strong> was most likely missing — the AI understands the task, role, and limits but lacks the background needed to know what &quot;this&quot; or &quot;it&quot; refers to.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Goal</b>: the goal is stated as clear, so it is present.</span><span class='qd'><b>Constraints</b>: constraints are present per the scenario.</span><span class='qd'><b>Persona</b>: the persona is present per the scenario.</span>" },
{ id:"D2-089", domain:2, obj:"2.5", diff:"medium", q:"When is a longer, more detailed prompt genuinely warranted?", options:["For complex or high-stakes tasks where role, context, and constraints all shape the outcome","For every prompt, no matter how simple","Only when converting units","Never, since short prompts are always better"], answer:0, explain:"<strong>For complex or high-stakes tasks where role, context, and constraints all shape the outcome</strong> — detail scales with task complexity, so involved tasks justify richer prompts.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>For every prompt, no matter how simple</b>: simple tasks do not need heavy detail.</span><span class='qd'><b>Only when converting units</b>: unit conversion is trivial and needs little detail.</span><span class='qd'><b>Never, since short prompts are always better</b>: short prompts underperform on complex tasks.</span>" },
{ id:"D2-090", domain:2, obj:"2.5", diff:"hard", q:"Which fully assembled prompt is strongest for planning a lesson?", options:["&quot;Plan a lesson about the water cycle.&quot;","&quot;Act as an elementary science teacher. My class is 24 fourth-graders new to the water cycle. Plan a 40-minute lesson with one hands-on activity, listed as objectives, steps, and a wrap-up.&quot;","&quot;You are a teacher; water cycle; make it good.&quot;","&quot;The water cycle has evaporation and condensation.&quot;"], answer:1, explain:"<strong>&quot;Act as an elementary science teacher. My class is 24 fourth-graders new to the water cycle. Plan a 40-minute lesson with one hands-on activity, listed as objectives, steps, and a wrap-up.&quot;</strong> combines persona, context, goal, and format constraints into one complete prompt.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;Plan a lesson about the water cycle.&quot;</b>: this is a bare goal without context or constraints.</span><span class='qd'><b>&quot;You are a teacher; water cycle; make it good.&quot;</b>: this is vague and gives no real structure or details.</span><span class='qd'><b>&quot;The water cycle has evaporation and condensation.&quot;</b>: this is context alone with no request.</span>" },
{ id:"D2-091", domain:2, obj:"2.5", diff:"medium", q:"A prompt improvement process might follow which loop?", options:["Write once and never change it","Attach files until the answer improves","Write a draft prompt, review the AI's output, then refine the prompt and try again","Only shorten the prompt each time"], answer:2, explain:"<strong>Write a draft prompt, review the AI's output, then refine the prompt and try again</strong> describes iterating, which steadily improves results.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Write once and never change it</b>: refusing to iterate wastes the chance to improve weak output.</span><span class='qd'><b>Attach files until the answer improves</b>: piling on files is not a reliable refinement method.</span><span class='qd'><b>Only shorten the prompt each time</b>: shortening alone ignores adding missing goal, context, or constraints.</span>" },
{ id:"D2-092", domain:2, obj:"2.5", diff:"hard", q:"You must decide how much detail to include for the task &quot;summarize this attached article in one sentence.&quot; Which choice reflects proper right-sizing?", options:["Add a detailed persona, background history, and five constraints","Attach several unrelated articles for comparison","Leave out the article and describe it vaguely","Provide the article and a clear one-sentence goal, with minimal extra detail"], answer:3, explain:"<strong>Provide the article and a clear one-sentence goal, with minimal extra detail</strong> matches the simple task: the source plus a precise goal is enough, and extra layers would be overload.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Add a detailed persona, background history, and five constraints</b>: this over-engineers a one-sentence summary.</span><span class='qd'><b>Attach several unrelated articles for comparison</b>: unrelated articles add noise the task does not need.</span><span class='qd'><b>Leave out the article and describe it vaguely</b>: omitting the source forces the AI to guess the content.</span>" },
{ id:"D2-093", domain:2, obj:"2.5", diff:"medium", q:"Which revision best turns &quot;help me plan a party&quot; into a right-sized, complete prompt?", options:["&quot;Plan a birthday party for 15 adults on a $300 budget; suggest a theme, food, and a simple timeline.&quot;","&quot;Help me plan a really great party, please.&quot;","&quot;You are a party planner. You are creative. You are fun.&quot;","&quot;Parties are enjoyable and bring people together.&quot;"], answer:0, explain:"<strong>&quot;Plan a birthday party for 15 adults on a $300 budget; suggest a theme, food, and a simple timeline.&quot;</strong> adds the goal, key context, a constraint, and the desired output pieces, right-sized to the task.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;Help me plan a really great party, please.&quot;</b>: &quot;really great&quot; adds no concrete detail.</span><span class='qd'><b>&quot;You are a party planner. You are creative. You are fun.&quot;</b>: this stacks vague persona lines with no goal or context.</span><span class='qd'><b>&quot;Parties are enjoyable and bring people together.&quot;</b>: this is filler with no request.</span>" },
{ id:"D2-094", domain:2, obj:"2.5", diff:"hard", q:"A prompt includes a goal, context, and constraints but the tone of the output feels wrong for the audience. Which adjustment most efficiently fixes it?", options:["Delete the context","Add a persona or a tone constraint aligned with the audience","Attach more files","Remove the goal"], answer:1, explain:"<strong>Add a persona or a tone constraint aligned with the audience</strong> directly targets the tone mismatch by telling the AI the voice to use.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Delete the context</b>: removing context would worsen relevance, not fix tone.</span><span class='qd'><b>Attach more files</b>: adding files does not set the voice.</span><span class='qd'><b>Remove the goal</b>: deleting the goal breaks the prompt entirely.</span>" },
{ id:"D2-095", domain:2, obj:"2.5", diff:"medium", q:"Which statement about assembling prompts is TRUE?", options:["You must always use all four building blocks in every prompt","Constraints should always come before the goal is known","Not every prompt needs all four blocks; include the ones the task actually requires","Persona is the only block that matters"], answer:2, explain:"<strong>Not every prompt needs all four blocks; include the ones the task actually requires</strong> — a simple task may need only a goal, while a complex one benefits from all four.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>You must always use all four building blocks in every prompt</b>: forcing all four onto trivial tasks causes overload.</span><span class='qd'><b>Constraints should always come before the goal is known</b>: you cannot sensibly set limits before you know the deliverable.</span><span class='qd'><b>Persona is the only block that matters</b>: the goal is the indispensable block; persona is often optional.</span>" },
{ id:"D2-096", domain:2, obj:"2.5", diff:"hard", q:"An assembled prompt reads: &quot;Act as an HR specialist. Our startup has 12 employees and no formal PTO policy. Draft a simple paid-time-off policy in plain language, under 400 words, with sections for eligibility, accrual, and requests.&quot; Which building block is the length limit &quot;under 400 words&quot;?", options:["Goal","Persona","Context","Constraint"], answer:3, explain:"<strong>Constraint</strong> — &quot;under 400 words&quot; is a length limit on the output, which is a constraint.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Goal</b>: the goal is drafting the PTO policy, not the word cap.</span><span class='qd'><b>Persona</b>: the persona is &quot;act as an HR specialist.&quot;</span><span class='qd'><b>Context</b>: the context is the startup's size and lack of a policy, not the length limit.</span>" },
{ id:"D2-097", domain:2, obj:"2.5", diff:"medium", q:"In the same assembled prompt, &quot;Our startup has 12 employees and no formal PTO policy&quot; serves as the:", options:["Context","Goal","Constraint","Format"], answer:0, explain:"<strong>Context</strong> — the sentence describes the organization's situation, which is background the AI uses to tailor the policy.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Goal</b>: the goal is to draft the policy, not describe the company.</span><span class='qd'><b>Constraint</b>: it sets no limit on length, tone, or format.</span><span class='qd'><b>Format</b>: it does not specify a structure for the output.</span>" },
{ id:"D2-098", domain:2, obj:"2.5", diff:"hard", q:"A user's prompt keeps producing off-target results. Which troubleshooting step aligns with the building-block approach?", options:["Blame the AI and stop using it","Check which block is weak or missing — goal, persona, context, or constraints — and strengthen it","Always make the prompt shorter","Add unrelated files until it works"], answer:1, explain:"<strong>Check which block is weak or missing — goal, persona, context, or constraints — and strengthen it</strong> uses the framework to diagnose and fix the prompt systematically.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Blame the AI and stop using it</b>: this abandons the fixable prompt rather than improving it.</span><span class='qd'><b>Always make the prompt shorter</b>: shortening can remove needed detail and worsen results.</span><span class='qd'><b>Add unrelated files until it works</b>: irrelevant files add noise, not clarity.</span>" },
{ id:"D2-099", domain:2, obj:"2.5", diff:"medium", q:"Which prompt best balances completeness and conciseness for writing a brief LinkedIn post?", options:["&quot;Write a LinkedIn post.&quot;","&quot;Act as a world-famous influencer with millions of followers and craft an epic multi-paragraph saga about my certification.&quot;","&quot;Write a 3-sentence LinkedIn post announcing that I earned my project-management certification, in an upbeat, professional tone.&quot;","&quot;Certifications are valuable in today's job market.&quot;"], answer:2, explain:"<strong>&quot;Write a 3-sentence LinkedIn post announcing that I earned my project-management certification, in an upbeat, professional tone.&quot;</strong> gives a goal, context, length, and tone without excess — a right-sized, complete prompt.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;Write a LinkedIn post.&quot;</b>: this omits the topic, length, and tone.</span><span class='qd'><b>&quot;Act as a world-famous influencer... epic multi-paragraph saga...&quot;</b>: this over-inflates a brief post with needless persona and length.</span><span class='qd'><b>&quot;Certifications are valuable in today's job market.&quot;</b>: this is a statement with no request.</span>" },
{ id:"D2-100", domain:2, obj:"2.5", diff:"hard", q:"A colleague says &quot;more detail always makes a prompt better.&quot; What is the most accurate response using right-sizing principles?", options:["&quot;Agreed, so always write the longest prompt possible.&quot;","&quot;Detail never matters; keep every prompt to three words.&quot;","&quot;Only persona detail matters; other detail is useless.&quot;","&quot;Not quite — detail helps only when it is relevant; irrelevant detail can overload the AI and reduce quality.&quot;"], answer:3, explain:"<strong>&quot;Not quite — detail helps only when it is relevant; irrelevant detail can overload the AI and reduce quality.&quot;</strong> captures right-sizing: match the amount of detail to what the task needs.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;Agreed, so always write the longest prompt possible.&quot;</b>: maximum length adds noise and can degrade results.</span><span class='qd'><b>&quot;Detail never matters; keep every prompt to three words.&quot;</b>: too little detail leaves the AI guessing.</span><span class='qd'><b>&quot;Only persona detail matters; other detail is useless.&quot;</b>: goal, context, and constraints all matter, not just persona.</span>" }
);
